import express from "express";
import { lookupByChannelId, setConversationId } from "../services/channelBindingStore.js";
import { agentChat } from "../services/chat/agentChat.js";
import { logger } from "../services/logger.js";
import { completeChannelBinding } from "./channels.js";
import { getApplicationDataSource, isApplicationDatabaseConfigured } from "../db/applicationDataSource.js";

/**
 * Telegram webhook — Phase 6, task 6.2.
 *
 * Spec: design.md §9.2; D1.1–D1.4.
 *
 * Thin transport: verify secret → resolve channel binding → call agentChat
 * → deliver reply. No slash-command parsing (D1.4). No content branching.
 *
 * The strict refuse-to-start guard for TELEGRAM_SECRET lands in Phase 9.
 * For now: log + reject malformed requests.
 */

const router = express.Router();

const TELEGRAM_MAX_MESSAGE_LENGTH = 4096;

function splitMessage(text: string, maxLen: number): string[] {
  if (text.length <= maxLen) return [text];
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    chunks.push(remaining.slice(0, maxLen));
    remaining = remaining.slice(maxLen);
  }
  return chunks;
}

async function deliverTelegramReply(
  botToken: string,
  chatId: string,
  text: string
): Promise<void> {
  const chunks = splitMessage(text, TELEGRAM_MAX_MESSAGE_LENGTH);
  for (const chunk of chunks) {
    try {
      const response = await fetch(
        `https://api.telegram.org/bot${botToken}/sendMessage`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            chat_id: chatId,
            text: chunk,
            parse_mode: "Markdown",
            disable_web_page_preview: true,
          }),
        }
      );
      if (!response.ok) {
        const body = await response.text();
        logger.warn(`Telegram delivery failed: ${body.slice(0, 200)}`);
      }
    } catch (err) {
      logger.warn(`Telegram delivery error: ${(err as Error).message}`);
    }
  }
}

async function getBotTokenForUser(userId: string): Promise<string | null> {
  if (!isApplicationDatabaseConfigured()) return null;
  try {
    const ds = await getApplicationDataSource();
    const rows = await ds.query(
      `SELECT ciphertext FROM encrypted_secrets
        WHERE user_id = $1 AND secret_kind = 'telegram_bot_token'
        LIMIT 1`,
      [userId]
    ) as Array<{ ciphertext: Buffer }>;
    const row = rows[0];
    if (!row) return null;
    // Phase 1 identity encryption: ciphertext IS the plaintext
    return row.ciphertext.toString("utf-8");
  } catch {
    return null;
  }
}

router.post("/telegram/webhook", async (req, res) => {
  // 1. Verify secret token (Phase 9 adds the strict startup guard)
  const secret = req.headers["x-telegram-bot-api-secret-token"];
  if (process.env["TELEGRAM_SECRET"] && secret !== process.env["TELEGRAM_SECRET"]) {
    if (isApplicationDatabaseConfigured()) {
      try {
        const ds = await getApplicationDataSource();
        await ds.query(
          `INSERT INTO admin_audit_log
             (actor_admin_id, action_type, target_user_id, args_json, result_status, request_id, ip_address, occurred_at)
           VALUES ('telegram_webhook', 'telegram_webhook_signature_failed', NULL, '{}'::jsonb, 'rejected', gen_random_uuid()::text, $1, NOW())`,
          [req.ip ?? null]
        );
      } catch { /* audit failure must not block */ }
    }
    res.status(200).json({ ok: true }); // Telegram requires 200
    return;
  }

  try {
    const update = req.body;
    const message = update?.message;
    if (!message?.text || !message?.chat?.id) {
      res.json({ ok: true });
      return;
    }

    const chatId = String(message.chat.id);
    const text = (message.text as string).trim();

    // 2. Handle channel-binding connect code
    const connectMatch = text.match(/^(?:\/connect\s+|connect\s+)([A-Fa-f0-9]{6})$/i);
    if (connectMatch) {
      const code = connectMatch[1]!;
      const result = await completeChannelBinding(code, "telegram", chatId);
      if (result.success && result.userId) {
        const botToken = await getBotTokenForUser(result.userId);
        if (botToken) {
          await deliverTelegramReply(botToken, chatId, result.message);
        }
      }
      res.json({ ok: true });
      return;
    }

    // 3. Resolve channel binding (D1.1)
    const binding = await lookupByChannelId("telegram", chatId);
    if (!binding) {
      if (isApplicationDatabaseConfigured()) {
        try {
          const ds = await getApplicationDataSource();
          await ds.query(
            `INSERT INTO admin_audit_log
               (actor_admin_id, action_type, target_user_id, args_json, result_status, request_id, ip_address, occurred_at)
             VALUES ('telegram_webhook', 'unknown_channel', NULL, $1::jsonb, 'rejected', gen_random_uuid()::text, $2, NOW())`,
            [JSON.stringify({ chatId }), req.ip ?? null]
          );
        } catch { /* audit failure must not block */ }
      }
      res.json({ ok: true });
      return;
    }

    // 4. Resolve or create conversation id (D1.2)
    let conversationId = binding.conversationId ?? undefined;

    // 5. Call agentChat (D1.2)
    const result = await agentChat({
      userId: binding.userId,
      text,
      channel: "telegram",
      ...(conversationId ? { conversationId } : {}),
    });

    // Persist conversation id on the binding for future messages
    if (!binding.conversationId && result.conversationId) {
      await setConversationId("telegram", chatId, result.conversationId);
    }

    // 6. Deliver reply (D1.3) — length truncation only
    const botToken = await getBotTokenForUser(binding.userId);
    if (botToken) {
      await deliverTelegramReply(botToken, chatId, result.replyText);
    } else {
      logger.warn(`No bot token found for user ${binding.userId}, cannot deliver Telegram reply`);
    }

    res.json({ ok: true });
  } catch (err) {
    logger.error("Telegram webhook error", { err });
    res.json({ ok: true }); // Always 200 to Telegram
  }
});

export default router;

import { Router, type Response, type NextFunction } from "express";
import type { AuthenticatedRequest } from "../middleware/auth.js";
import type { UserWorkspace } from "../middleware/userIsolation.js";
import { listNotifications, markNotificationsRead } from "../services/notificationService.js";

const router = Router();

type AsyncHandler = (
  req: AuthenticatedRequest,
  res: Response,
  next: NextFunction
) => Promise<void>;

function handler(fn: AsyncHandler) {
  return (req: AuthenticatedRequest, res: Response, next: NextFunction) => {
    fn(req, res, next).catch(next);
  };
}

router.get(
  "/notifications",
  handler(async (req: AuthenticatedRequest, res: Response) => {
    const ws = res.locals["workspace"] as UserWorkspace;
    const limit = Math.min(Math.max(Number(req.query["limit"] ?? 20), 1), 100);
    const unreadOnly = String(req.query["unread"] ?? "false") === "true";
    const channelRaw = typeof req.query["channel"] === "string" ? req.query["channel"] : null;
    const channel =
      channelRaw === "web" || channelRaw === "telegram" || channelRaw === "whatsapp"
        ? channelRaw
        : null;

    const items = await listNotifications(ws.userId, {
      limit,
      unreadOnly,
      channel,
    });

    res.json({
      items,
      unreadCount: items.filter((item) => item.readAt === null).length,
    });
  })
);

router.post(
  "/notifications/read",
  handler(async (req: AuthenticatedRequest, res: Response) => {
    const ws = res.locals["workspace"] as UserWorkspace;
    const ids = Array.isArray(req.body?.ids) ? req.body.ids.filter((id: unknown) => typeof id === "string") : [];
    const updated = await markNotificationsRead(ws.userId, ids);
    res.json({ updated });
  })
);

export default router;

import { useEffect, useRef, useState } from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { QueryClient, QueryClientProvider, useQuery } from "@tanstack/react-query";
import { useAuthStore } from "./store/authStore";
import { usePreferencesStore } from "./store/preferencesStore";
import { t } from "./store/i18n";
import { BottomNav } from "./components/ui/BottomNav";
import { ToastContainer } from "./components/ui/Toast";
import { Login } from "./pages/Login";
import { Onboarding } from "./pages/Onboarding";
import { Portfolio } from "./pages/Portfolio";
import { Alerts } from "./pages/Alerts";
import { Reports } from "./pages/Reports";
import { Strategies } from "./pages/Strategies";
import { Controls } from "./pages/Controls";
import { Settings } from "./pages/Settings";
import { Admin } from "./pages/Admin";
import { Chat } from "./pages/Chat";
import { PointsBadge } from "./components/ui/PointsBadge";
import { fetchOnboardStatus } from "./api/onboarding";
import { fetchControlState } from "./api/control";
import { fetchNotifications, markNotificationsRead } from "./api/notifications";
import { ControlBanner } from "./components/ControlBanner";
import { SuspensionPage } from "./pages/SuspensionPage";
import { Spinner } from "./components/ui/Spinner";
import { useToastStore } from "./store/toastStore";

const queryClient = new QueryClient({
 defaultOptions: {
 queries: {
 retry: 1,
 staleTime: 30_000,
 refetchOnWindowFocus: false,
 },
 },
});

function ProtectedRoute({ children }: { children: React.ReactNode }) {
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated);
  const language = usePreferencesStore((s) => s.language);
  const [healthDismissed, setHealthDismissed] = useState(false);
  const showToast = useToastStore((s) => s.show);
  const seenNotificationIds = useRef<Set<string>>(new Set());

  const { data: onboardStatus, isLoading, error } = useQuery({
    queryKey: ["onboard-status"],
    queryFn: fetchOnboardStatus,
    enabled: isAuthenticated,
    staleTime: 60_000,
  });

  const { data: controlState } = useQuery({
    queryKey: ["control-state"],
    queryFn: fetchControlState,
    enabled: isAuthenticated,
    refetchInterval: 30_000,
    staleTime: 15_000,
    retry: false,
  });

  const { data: notifications } = useQuery({
    queryKey: ["web-notifications"],
    queryFn: () => fetchNotifications({ channel: "web", unread: true, limit: 10 }),
    enabled: isAuthenticated,
    refetchInterval: 15_000,
    staleTime: 5_000,
  });

  useEffect(() => {
    if (!notifications?.items.length) return;
    const unseen = notifications.items.filter((item) => !seenNotificationIds.current.has(item.id));
    if (unseen.length === 0) return;
    const ids = unseen.map((item) => item.id);
    const grouped = new Map<string, typeof unseen[number]>();
    for (const item of unseen) {
      seenNotificationIds.current.add(item.id);
      const key = item.batchId ? `${item.category}:${item.batchId}` : item.id;
      if (!grouped.has(key)) grouped.set(key, item);
    }
    for (const item of grouped.values()) {
      const message = item.body ? `${item.title}: ${item.body}` : item.title;
      showToast(message, item.category === "daily_brief" ? "info" : "warning");
    }
    void markNotificationsRead(ids);
  }, [notifications?.items, showToast]);

  if (!isAuthenticated) return <Navigate to="/login" replace />;

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[var(--color-bg-base)]">
        <Spinner size="lg" />
      </div>
    );
  }

  if (error || !onboardStatus) return <>{children}</>;

  if (!onboardStatus.portfolioLoaded || onboardStatus.guidanceStepPending) {
    return <Navigate to="/onboarding" replace />;
  }

  // Suspended: full-screen suspension page, no navigation
  if (controlState?.restriction === "suspended") {
    return <SuspensionPage reason={controlState.reason} />;
  }

  const showHealthBanner = !healthDismissed && onboardStatus.agentHealthy === false;

  return (
    <>
      {controlState && <ControlBanner state={controlState} />}
      {showHealthBanner && (
        <div
          className="sticky top-0 z-40 flex items-center justify-between gap-2 px-4 py-2 text-sm font-medium"
          style={{
            background: "rgba(239,68,68,0.12)",
            borderBottom: "1px solid rgba(239,68,68,0.3)",
            color: "var(--color-accent-red)",
          }}
        >
          <span>{t("healthBanner", language)}</span>
          <button
            onClick={() => setHealthDismissed(true)}
            className="ml-4 shrink-0 text-base leading-none opacity-70 hover:opacity-100"
          >×</button>
        </div>
      )}
      <PointsBadge />
      <div>{children}</div>
    </>
  );
}

// Separate route guard for onboarding - prevents returning to completed onboarding
function OnboardingRoute() {
 const isAuthenticated = useAuthStore((s) => s.isAuthenticated);

 const { data: onboardStatus, isLoading } = useQuery({
   queryKey: ["onboard-status"],
   queryFn: fetchOnboardStatus,
   enabled: isAuthenticated,
   staleTime: 60_000,
 });

 if (!isAuthenticated) return <Navigate to="/login" replace />;

 if (isLoading) {
   return (
     <div className="flex items-center justify-center min-h-screen bg-[var(--color-bg-base)]">
       <Spinner size="lg" />
     </div>
   );
 }

 // If portfolio already loaded, send them to portfolio - no going back
 if (onboardStatus?.portfolioLoaded && !onboardStatus.guidanceStepPending) {
   return <Navigate to="/portfolio" replace />;
 }

 return <Onboarding />;
}

function AppLayout({ children }: { children: React.ReactNode }) {
 return (
 <div className="bg-[var(--color-bg-base)] min-h-screen">
 <div className="page-content">{children}</div>
 <BottomNav />
 </div>
 );
}

export default function App() {
 const isAuthenticated = useAuthStore((s) => s.isAuthenticated);

 return (
 <QueryClientProvider client={queryClient}>
 <BrowserRouter>
 <Routes>
 <Route path="/login" element={<Login />} />
 <Route path="/onboarding" element={<OnboardingRoute />} />
 <Route path="/" element={
 isAuthenticated
 ? <Navigate to="/portfolio" replace />
 : <Navigate to="/login" replace />
 } />
 <Route path="/portfolio" element={
 <ProtectedRoute>
 <AppLayout><Portfolio /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/alerts" element={
 <ProtectedRoute>
 <AppLayout><Alerts /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/reports" element={
 <ProtectedRoute>
 <AppLayout><Reports /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/strategies" element={
 <ProtectedRoute>
 <AppLayout><Strategies /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/settings" element={
 <ProtectedRoute>
 <AppLayout><Settings /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/controls" element={
 <ProtectedRoute>
 <AppLayout><Controls /></AppLayout>
 </ProtectedRoute>
 } />
 <Route path="/admin" element={<Admin />} />
 <Route path="/chat" element={
 <ProtectedRoute>
 <AppLayout><Chat /></AppLayout>
 </ProtectedRoute>
 } />
 </Routes>
 <ToastContainer />
 </BrowserRouter>
 </QueryClientProvider>
 );
}

import { useState, useMemo, useEffect } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { ChevronDown, ChevronUp, Layers3, Plus, RefreshCw } from "lucide-react";
import {
  fetchPortfolio,
  fetchVerdicts,
  addAccount,
  deleteAccount,
  deletePosition,
} from "../api/portfolio";
import { fetchOnboardStatus } from "../api/onboarding";
import { fetchJobs } from "../api/jobs";
import { triggerJob } from "../api/jobs";
import { PositionRow } from "../components/portfolio/PositionRow";
import { PositionDetailModal } from "../components/portfolio/PositionDetailModal";
import { StrategyModal } from "../components/portfolio/StrategyModal";
import { Spinner } from "../components/ui/Spinner";
import { ErrorState } from "../components/ui/ErrorState";
import { EmptyState } from "../components/ui/EmptyState";
import { Card } from "../components/ui/Card";
import { formatILS, timeAgo, formatPct } from "../utils/format";
