  { id: "quick_check", label: "Quick check" },
  { id: "new_ideas", label: "New ideas" },
];

const MODE_META: Record<string, { label: string; icon: ReactElement }> = {
  quick_check: {
    label: "Quick check",
    icon: <Radar size={12} />,
  },
  daily_brief: {
    label: "Daily brief",
