      {c.pattern ? <p className="text-[11px] italic text-[var(--color-fg-muted)]">{c.pattern as string}</p> : null}
      {c.technicalView ? <BodyText text={c.technicalView as string} /> : null}
      <SourceLinks sources={c.sources} />
