import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { fetchStrategies } from "../api/strategies";
import { StrategyModal } from "../components/portfolio/StrategyModal";
import { VerdictBadge, ConfidenceBadge } from "../components/ui/Badge";
import { Spinner } from "../components/ui/Spinner";
import { ErrorState } from "../components/ui/ErrorState";
import { EmptyState } from "../components/ui/EmptyState";
import { formatILS, timeAgo } from "../utils/format";
import { usePreferencesStore } from "../store/preferencesStore";
import { t, tConfidence, tTimeframe } from "../store/i18n";
import type { Verdict, StrategyRow } from "../types/api";

const VERDICT_ORDER: Record<Verdict, number> = {
  SELL: 0,
  CLOSE: 0,
  REDUCE: 1,
  BUY: 2,
  ADD: 2,
  HOLD: 3,
};

const VERDICT_FILTER_OPTIONS = ["All", "BUY", "ADD", "HOLD", "REDUCE", "SELL", "CLOSE"] as const;
type StrategyScope = "portfolio" | "tracking";

function strategyScope(strategy: StrategyRow): StrategyScope {
  return strategy.scope ?? (strategy.inPortfolio ? "portfolio" : "tracking");
}

function formatTrackingMeta(strategy: StrategyRow): string | null {
  if (strategyScope(strategy) !== "tracking") return null;
  const parts = [
    strategy.stance ? strategy.stance.replace("_", " ") : null,
    typeof strategy.potentialScore === "number" ? `${strategy.potentialScore}/100 potential` : null,
    typeof strategy.urgencyScore === "number" ? `${strategy.urgencyScore}/100 urgency` : null,
    typeof strategy.suggestedAllocationPct === "number" ? `${strategy.suggestedAllocationPct.toFixed(1)}% suggested` : null,
  ].filter((part): part is string => part !== null);
  return parts.length > 0 ? parts.join(" · ") : "Tracked idea";
}

function sortStrategies(strategies: StrategyRow[]): StrategyRow[] {
  return [...strategies].sort((a, b) => {
    const orderA = VERDICT_ORDER[a.verdict] ?? 99;
    const orderB = VERDICT_ORDER[b.verdict] ?? 99;
    if (orderA !== orderB) return orderA - orderB;
    return a.ticker.localeCompare(b.ticker);
  });
}

export function Strategies() {
  const language = usePreferencesStore((s) => s.language);
  const [selectedTicker, setSelectedTicker] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [verdictFilter, setVerdictFilter] = useState<string>("All");
  const [scope, setScope] = useState<StrategyScope>("portfolio");

  const { data, isLoading, error, refetch } = useQuery({
    queryKey: ["strategies"],
    queryFn: fetchStrategies,
    staleTime: 60_000,
  });

  const filtered = useMemo(() => {
    if (!data) return [];
    let list = sortStrategies(data.strategies);
    list = list.filter((strategy) => strategyScope(strategy) === scope);
    if (search.trim()) {
      const q = search.trim().toUpperCase();
      list = list.filter((s) => s.ticker.includes(q));
    }
    if (verdictFilter !== "All") {
      list = list.filter((s) => s.verdict === verdictFilter);
    }
    return list;
  }, [data, search, verdictFilter, scope]);

  const scopedTotal = useMemo(() => {
    if (!data) return 0;
    return data.strategies.filter((strategy) => strategyScope(strategy) === scope).length;
  }, [data, scope]);

  const isEmpty = !data || scopedTotal === 0;
  const noResults = !isEmpty && filtered.length === 0;

  return (
    <>
      <div style={{ padding: "20px 16px 0" }}>
        <h1 style={{ fontSize: "var(--text-lg)", fontWeight: "var(--weight-bold)", color: "var(--text-primary)", margin: 0 }}>
          {t("strategies", language)}
        </h1>
      </div>

      {/* Filters */}
      <div className="px-4 pt-3 pb-2 space-y-2">
        <div className="inline-flex rounded-lg border border-[var(--color-border)] bg-[var(--color-bg-muted)] p-1">
          {([
            ["portfolio", t("strategyTabPortfolio", language)],
            ["tracking", t("strategyTabNonPortfolio", language)],
          ] as const).map(([nextScope, label]) => (
            <button
              key={nextScope}
              onClick={() => setScope(nextScope)}
              className={`rounded-md px-3 py-1.5 text-xs font-bold transition-colors ${
                scope === nextScope
                  ? "bg-[var(--color-bg-subtle)] text-[var(--color-fg-default)] shadow-sm"
                  : "text-[var(--color-fg-muted)]"
              }`}
            >
              {label}
            </button>
          ))}
        </div>
        <input
          type="text"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder={t("searchTicker", language)}
          className="w-full bg-[var(--color-bg-muted)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-fg-default)] outline-none focus:border-[var(--color-accent-blue)]"
        />
        <div className="flex gap-1.5 flex-wrap">
          {VERDICT_FILTER_OPTIONS.map((opt) => (
            <button
              key={opt}
              onClick={() => setVerdictFilter(opt)}
              className={`px-2.5 py-1 rounded-full text-[10px] font-bold transition-colors ${
                verdictFilter === opt
                  ? "bg-[var(--color-accent-blue)] text-white"
                  : "bg-[var(--color-bg-muted)] text-[var(--color-fg-muted)] border border-[var(--color-border)]"
              }`}
            >
              {opt}
            </button>
          ))}
        </div>
      </div>

      <div className="px-4 pb-8">
        {isLoading && (
          <div className="flex items-center justify-center py-12">
            <Spinner size="lg" />
          </div>
        )}

        {error && <ErrorState message={t("errorLoadStrategies", language)} onRetry={refetch} />}

        {isEmpty && <EmptyState message={t("emptyStrategies", language)} icon="🎯" />}

        {noResults && (
          <EmptyState message={t("noStrategyMatches", language)} icon="🔍" />
        )}

        {/* Mobile card list */}
        {filtered.length > 0 && (
          <>
            <div className="md:hidden space-y-2 pt-2">
              {filtered.map((s) => (
                <div
                  key={s.ticker}
                  onClick={() => setSelectedTicker(s.ticker)}
                  className="bg-[var(--color-bg-subtle)] border border-[var(--color-border)] rounded-lg px-3 py-3 cursor-pointer active:opacity-80"
                >
                  <div className="flex items-start justify-between gap-2 mb-1">
                    <div className="flex items-center gap-1.5">
                      <span className="font-mono font-bold text-sm text-[var(--color-fg-default)]">{s.ticker}</span>
                      <VerdictBadge verdict={s.verdict} size="sm" />
                      {s.hasExpiredCatalysts && <span className="text-[10px]">🔴</span>}
                    </div>
                    <div className="text-[10px] text-[var(--color-fg-subtle)] shrink-0">{timeAgo(s.updatedAt)}</div>
                  </div>
                  <div className="text-[10px] text-[var(--color-fg-muted)] mb-1.5">
                    {tConfidence(s.confidence, language)} · {tTimeframe(s.timeframe, language)} · {formatILS(s.positionSizeILS)}
                  </div>
                  {formatTrackingMeta(s) ? (
                    <div className="text-[10px] text-[var(--color-accent-blue)] mb-1.5">
                      {formatTrackingMeta(s)}
                    </div>
                  ) : null}
                  <p className="text-xs text-[var(--color-fg-muted)] line-clamp-2 leading-snug">
                    {s.reasoning}
                  </p>
                  {s.hasExpiredCatalysts && (
                    <p className="text-[10px] text-[var(--color-accent-red)] mt-1">🔴 {t("expiredCatalyst", language)}</p>
                  )}
                </div>
              ))}
            </div>

            {/* Desktop table */}
            <div className="hidden md:block mt-2 bg-[var(--color-bg-subtle)] border border-[var(--color-border)] rounded-lg overflow-hidden">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-[var(--color-border)]">
                    {[t("colTicker",language), t("colVerdict",language), t("colConfidence",language), t("colTimeframe",language), t("colSize",language), t("colWeightPct",language), scope === "tracking" ? "Tracking" : t("colReasoning",language), t("colUpdated",language), "⚠️"].map((h) => (
                      <th key={h} className="px-3 py-2 text-left text-[10px] font-medium text-[var(--color-fg-subtle)] uppercase">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((s) => (
                    <tr
                      key={s.ticker}
                      onClick={() => setSelectedTicker(s.ticker)}
                      className="cursor-pointer hover:bg-[var(--color-bg-muted)] border-b border-[var(--color-border-muted)] last:border-0"
                    >
                      <td className="px-3 py-2.5">
                        <span className="font-mono font-bold text-sm text-[var(--color-fg-default)]">{s.ticker}</span>
                      </td>
                      <td className="px-3 py-2.5"><VerdictBadge verdict={s.verdict} size="sm" /></td>
                      <td className="px-3 py-2.5"><ConfidenceBadge confidence={tConfidence(s.confidence, language)} /></td>
                      <td className="px-3 py-2.5 text-sm text-[var(--color-fg-muted)]">{tTimeframe(s.timeframe, language)}</td>
                      <td className="px-3 py-2.5 text-sm text-[var(--color-fg-muted)] text-right">{formatILS(s.positionSizeILS)}</td>
                      <td className="px-3 py-2.5 text-sm text-[var(--color-fg-muted)] text-right">{(s.positionWeightPct ?? 0).toFixed(1)}%</td>
                      <td className="px-3 py-2.5 text-xs text-[var(--color-fg-muted)] max-w-[200px] truncate">
                        {scope === "tracking" ? formatTrackingMeta(s) ?? s.reasoning : s.reasoning}
                      </td>
                      <td className="px-3 py-2.5 text-[10px] text-[var(--color-fg-subtle)]">{timeAgo(s.updatedAt)}</td>
                      <td className="px-3 py-2.5 text-center">{s.hasExpiredCatalysts ? "🔴" : ""}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </>
        )}
      </div>

      <StrategyModal
        ticker={selectedTicker}
        onClose={() => setSelectedTicker(null)}
      />
    </>
  );
}

import { useDeferredValue, useMemo, useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { BellRing, ChevronDown, ChevronUp, Newspaper, Radar, Search, Sparkles } from "lucide-react";
import { Link } from "react-router-dom";
import { Spinner } from "../components/ui/Spinner";
import { EmptyState } from "../components/ui/EmptyState";
import { ErrorState } from "../components/ui/ErrorState";
import { usePreferencesStore } from "../store/preferencesStore";
import { t } from "../store/i18n";
import { apiClient } from "../api/client";
import type { FeedPageResponse, FeedItem } from "../types/api";

type FeedFilter =
  | "all"
  | "events"
  | "quick_check"
  | "daily_brief"
  | "deep_dive"
  | "new_ideas"
  | "full_report";

const FILTERS: Array<{ id: FeedFilter; label: string }> = [
  { id: "all", label: "All" },
  { id: "events", label: "News" },
  { id: "quick_check", label: "Quick" },
  { id: "daily_brief", label: "Daily" },
  { id: "deep_dive", label: "Deep" },
  { id: "new_ideas", label: "Ideas" },
  { id: "full_report", label: "Weekly" },
];

const toneClasses: Record<FeedItem["tone"], string> = {
  amber: "border-amber-300/25 bg-[linear-gradient(180deg,rgba(245,158,11,0.10),rgba(17,24,39,0.96))]",
  emerald: "border-emerald-300/25 bg-[linear-gradient(180deg,rgba(16,185,129,0.10),rgba(17,24,39,0.96))]",
  rose: "border-rose-300/25 bg-[linear-gradient(180deg,rgba(244,63,94,0.10),rgba(17,24,39,0.96))]",
  sky: "border-sky-300/25 bg-[linear-gradient(180deg,rgba(56,189,248,0.10),rgba(17,24,39,0.96))]",
  slate: "border-[var(--color-border)] bg-[linear-gradient(180deg,rgba(148,163,184,0.06),rgba(17,24,39,0.96))]",
};

function iconForItem(item: FeedItem) {
  if (item.kind === "market_news") return <Newspaper size={14} />;
  if (item.mode === "quick_check") return <Radar size={14} />;
  if (item.mode === "new_ideas") return <Sparkles size={14} />;
  return <BellRing size={14} />;
}

function modeLabel(item: FeedItem): string {
  if (item.kind === "market_news") return "Market News";
  if (item.mode === "full_report") return "Weekly report";
  return item.mode.replace(/_/g, " ");
}

export function Alerts() {
  const language = usePreferencesStore((s) => s.language);
  const [filter, setFilter] = useState<FeedFilter>("all");
  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const deferredSearch = useDeferredValue(search.trim());
  const [expanded, setExpanded] = useState<Record<string, boolean>>({});


  const feedPath = useMemo(() => {
    const params = new URLSearchParams();
    if (filter !== "all") params.set("mode", filter);
    if (deferredSearch) params.set("q", deferredSearch);
    const suffix = params.toString();
    return `/reports/feed/${page}${suffix ? `?${suffix}` : ""}`;
  }, [deferredSearch, filter, page]);

  const { data, isLoading, error, refetch } = useQuery({
    queryKey: ["feed-page", page, filter, deferredSearch],
    queryFn: () => apiClient.get<FeedPageResponse>(feedPath).then((r) => r.data),
    staleTime: 10_000,
    refetchInterval: 15_000,
  });

  const items = data?.items ?? [];

  if (isLoading) {
    return (
      <div className="flex h-48 items-center justify-center">
        <Spinner size="lg" />
      </div>
    );
  }

  if (error) {
    return <ErrorState message={t("errorLoadAlerts", language)} onRetry={refetch} />;
  }

  return (
    <>
      <div style={{ padding: "20px 16px 0" }}>
        <h1 style={{ fontSize: "var(--text-lg)", fontWeight: "var(--weight-bold)", color: "var(--text-primary)", margin: 0 }}>
          {t("alerts", language)}
        </h1>
      </div>

      <div className="space-y-3 px-4 pb-8">
        <div className="space-y-3 border-b border-[var(--color-border)] px-4 py-3" style={{ marginLeft: -16, marginRight: -16 }}>
          <label className="flex items-center gap-2 rounded-2xl border border-[var(--color-border)] bg-[var(--color-bg-subtle)] px-3 py-2.5">
            <Search size={15} className="text-[var(--color-fg-subtle)]" />
            <input
              value={search}
              onChange={(event) => {
                setSearch(event.target.value);
                setPage(1);
              }}
              placeholder="Search ticker, mode, reasoning"
              className="w-full bg-transparent text-sm text-[var(--color-fg-default)] outline-none placeholder:text-[var(--color-fg-subtle)]"
            />
          </label>

          <div className="flex gap-2 overflow-x-auto">
            {FILTERS.map((option) => (
              <button
                key={option.id}
                onClick={() => {
                  setFilter(option.id);
                  setPage(1);
                }}
                className={`rounded-full border px-3 py-1.5 text-xs font-medium ${
                  filter === option.id
                    ? "border-[var(--color-accent-blue)] bg-[var(--color-accent-blue)]/15 text-[var(--color-fg-default)]"
                    : "border-[var(--color-border)] bg-[var(--color-bg-subtle)] text-[var(--color-fg-muted)]"
                }`}
              >
                {option.label}
              </button>
            ))}
          </div>
        </div>

        {!data || items.length === 0 ? (
          <EmptyState message={t("emptyAlerts", language)} icon="📰" />
        ) : (
          items.map((item) => {
            const isExpanded = expanded[item.id] ?? false;
            return (
              <article key={item.id} className={`overflow-hidden rounded-3xl border shadow-sm ${toneClasses[item.tone]}`}>
                <button
                  onClick={() => setExpanded((prev) => ({ ...prev, [item.id]: !isExpanded }))}
                  className="w-full px-4 py-4 text-left"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div className="min-w-0">
                      <div className="mb-1 flex items-center gap-2 text-[11px] uppercase tracking-[0.18em] text-[var(--color-fg-subtle)]">
                        <span className="inline-flex h-7 w-7 items-center justify-center rounded-full border border-white/10 bg-black/10">
                          {iconForItem(item)}
                        </span>
                        <span>{modeLabel(item)}</span>
                      </div>
                      <h2 className="truncate text-sm font-bold text-[var(--color-fg-default)]">{item.title}</h2>
                      <p className="mt-1 text-xs text-[var(--color-fg-subtle)]">
                        {new Date(item.createdAt).toLocaleString()}
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      {item.kind !== "market_news" && (
                        <div className="rounded-full border border-white/10 bg-black/10 px-2.5 py-1 text-[10px] font-bold text-[var(--color-fg-muted)]">
                          {item.tickerCount} ticker{item.tickerCount === 1 ? "" : "s"}
                        </div>
                      )}
                      {isExpanded ? <ChevronUp size={16} className="text-[var(--color-fg-muted)]" /> : <ChevronDown size={16} className="text-[var(--color-fg-muted)]" />}
                    </div>
                  </div>

                  <p className="mt-3 text-sm leading-6 text-[var(--color-fg-muted)]">{item.summary}</p>

                  <div className="mt-3 flex flex-wrap gap-2">
                    {item.highlights.slice(0, 3).map((highlight) => (
                      <span
                        key={highlight}
                        className="rounded-full border border-white/10 bg-black/10 px-2.5 py-1 text-[10px] font-medium text-[var(--color-fg-muted)]"
                      >
                        {highlight}
                      </span>
                    ))}
                  </div>
                </button>

                {isExpanded && (
                  <div className="border-t border-white/10 px-4 py-4">
                    {item.kind === "market_news" ? (
                      <div className="space-y-3">
                        <div className="rounded-2xl border border-[var(--color-border)] bg-black/10 p-3">
                          <p className="text-[10px] uppercase tracking-[0.18em] text-[var(--color-fg-subtle)]">Ticker</p>
                          <p className="mt-2 text-sm font-bold text-[var(--color-fg-default)]">{item.event?.ticker}</p>
                        </div>
                        <div className="rounded-2xl border border-[var(--color-border)] bg-black/10 p-3">
                          <p className="text-[10px] uppercase tracking-[0.18em] text-[var(--color-fg-subtle)]">Source</p>
                          <p className="mt-2 text-sm text-[var(--color-fg-default)]">{item.event?.source ?? "feed"}</p>
                        </div>
                        {item.event?.url ? (
                          <a
                            href={item.event.url}
                            target="_blank"
                            rel="noreferrer"
                            className="inline-flex rounded-full border border-[var(--color-border)] px-3 py-1.5 text-xs font-medium text-[var(--color-fg-default)]"
                          >
                            Open source
                          </a>
                        ) : null}
                      </div>
                    ) : (
                      <div className="space-y-3">
                        {item.dailyBrief ? (
                          <div className="rounded-2xl border border-[var(--color-border)] bg-black/10 p-3">
                            <p className="text-[10px] uppercase tracking-[0.18em] text-[var(--color-fg-subtle)]">Portfolio view</p>
                            <p className="mt-2 text-sm text-[var(--color-fg-default)]">{item.dailyBrief.headline ?? item.summary}</p>
                            {item.dailyBrief.today ? <p className="mt-2 text-xs leading-5 text-[var(--color-fg-muted)]">{item.dailyBrief.today}</p> : null}
                            {item.dailyBrief.tomorrow ? <p className="mt-2 text-xs leading-5 text-[var(--color-fg-muted)]">{item.dailyBrief.tomorrow}</p> : null}
                            {item.dailyBrief.marketView ? <p className="mt-2 text-xs leading-5 text-[var(--color-fg-muted)]">{item.dailyBrief.marketView}</p> : null}
                            {item.dailyBrief.securityNote ? <p className="mt-2 text-xs leading-5 text-[var(--color-fg-default)]">{item.dailyBrief.securityNote}</p> : null}
                            {item.dailyBrief.dashboardPath ? (
                              <Link
                                to={item.dailyBrief.dashboardPath}
