import { useState, useRef, useEffect } from "react";
import { useMutation } from "@tanstack/react-query";
import { MessageCircle, Send, Loader2, AlertCircle, Plus } from "lucide-react";
import { sendChatMessage } from "../api/chat";
import { clsx } from "clsx";

/**
 * Dashboard chat pane — Phase 5, task 5.14.
 *
 * Conversation ID and messages are persisted to localStorage with a 14-day TTL
 * so the user can return to the same conversation across sessions.
 */

const STORAGE_KEY = "chat_session";
const TTL_MS = 14 * 24 * 60 * 60 * 1000; // 14 days

interface StoredSession {
  conversationId: string;
  messages: Message[];
  savedAt: number;
}

function loadSession(): StoredSession | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as StoredSession;
    if (Date.now() - parsed.savedAt > TTL_MS) {
      localStorage.removeItem(STORAGE_KEY);
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

function saveSession(conversationId: string, messages: Message[]): void {
  try {
    const session: StoredSession = { conversationId, messages, savedAt: Date.now() };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(session));
  } catch {
    // localStorage full — ignore
  }
}

function clearSession(): void {
  localStorage.removeItem(STORAGE_KEY);
}

/**
 * Dashboard chat pane — Phase 5, task 5.14.
 *
 * Spec: design.md §9.1; D3.1, D3.2.
 *
 * Renders streamed or final replies as plain text. No client-side tool-call
 * interpretation (D3.2). Conversation ID is persisted in component state so
 * the same conversation continues across messages in the same session.
 */

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
  isError?: boolean;
}

export function Chat() {
  const stored = loadSession();
  const [messages, setMessages] = useState<Message[]>(stored?.messages ?? []);
  const [input, setInput] = useState("");
  const [conversationId, setConversationId] = useState<string | undefined>(stored?.conversationId);
  const bottomRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLTextAreaElement>(null);

  // Persist session whenever messages or conversationId change
  useEffect(() => {
    if (conversationId && messages.length > 0) {
      saveSession(conversationId, messages);
    }
  }, [conversationId, messages]);

  const handleNewChat = () => {
    clearSession();
    setMessages([]);
    setConversationId(undefined);
    setInput("");
  };

  const mutation = useMutation({
    mutationFn: ({ text, convId }: { text: string; convId?: string }) =>
      sendChatMessage(text, convId),
    onSuccess: (data) => {
      setConversationId(data.conversationId);
      setMessages((prev) => [
        ...prev,
        {
          id: `assistant-${Date.now()}`,
          role: "assistant",
          content: data.replyText,
        },
      ]);
    },
    onError: () => {
      setMessages((prev) => [
        ...prev,
        {
          id: `error-${Date.now()}`,
          role: "assistant",
          content: "Something went wrong. Please try again.",
          isError: true,
        },
      ]);
    },
  });

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, mutation.isPending]);

  const handleSend = () => {
    const text = input.trim();
    if (!text || mutation.isPending) return;

    setMessages((prev) => [
      ...prev,
      { id: `user-${Date.now()}`, role: "user", content: text },
    ]);
    setInput("");
    mutation.mutate({ text, convId: conversationId });
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div
      className="flex flex-col"
      style={{
        height: "calc(100dvh - 56px - env(safe-area-inset-bottom))",
        background: "var(--color-bg-base)",
      }}
    >
      {/* Header */}
      <div
        className="flex items-center justify-between gap-2 px-4 py-3 border-b"
        style={{ borderColor: "var(--color-border)", background: "var(--color-bg-subtle)" }}
      >
        <div className="flex items-center gap-2">
          <MessageCircle size={18} style={{ color: "var(--color-accent-blue)" }} />
          <span className="font-bold text-sm" style={{ color: "var(--color-fg-default)" }}>
            Portfolio Assistant
          </span>
          {conversationId && (
            <span className="text-[10px] px-1.5 py-0.5 rounded" style={{ background: "var(--color-bg-subtle)", color: "var(--color-fg-subtle)" }}>
              saved
            </span>
          )}
        </div>
        {messages.length > 0 && (
          <button
            onClick={handleNewChat}
            className="flex items-center gap-1 text-xs px-2.5 py-1.5 rounded-lg transition-colors"
            style={{ color: "var(--color-fg-muted)", background: "var(--color-bg-subtle)", border: "1px solid var(--color-border)" }}
            title="Start a new conversation"
          >
            <Plus size={12} />
            New
          </button>
        )}
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full gap-3 text-center">
            <MessageCircle size={40} style={{ color: "var(--color-fg-subtle)" }} />
            <p className="text-sm" style={{ color: "var(--color-fg-muted)" }}>
              Ask about your portfolio, strategies, or request an analysis.
            </p>
            <div className="flex flex-wrap gap-2 justify-center mt-2">
              {[
                "What's my portfolio looking like?",
                "Which positions need attention?",
                "Run a quick check on AAPL",
              ].map((suggestion) => (
                <button
                  key={suggestion}
                  onClick={() => {
                    setInput(suggestion);
                    inputRef.current?.focus();
                  }}
                  className="text-xs px-3 py-1.5 rounded-full border transition-colors"
                  style={{
                    borderColor: "var(--color-border)",
                    color: "var(--color-fg-muted)",
                    background: "var(--color-bg-subtle)",
                  }}
                >
                  {suggestion}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg) => (
          <div
            key={msg.id}
            className={clsx(
              "flex",
              msg.role === "user" ? "justify-end" : "justify-start"
            )}
          >
            <div
              className={clsx(
                "max-w-[85%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed",
                msg.role === "user"
                  ? "rounded-br-sm"
                  : "rounded-bl-sm"
              )}
              style={
                msg.role === "user"
                  ? {
                      background: "var(--color-accent-blue)",
                      color: "#fff",
                    }
                  : msg.isError
                  ? {
                      background: "rgba(239,68,68,0.1)",
                      color: "var(--color-accent-red)",
                      border: "1px solid rgba(239,68,68,0.2)",
                    }
                  : {
                      background: "var(--color-bg-subtle)",
                      color: "var(--color-fg-default)",
                      border: "1px solid var(--color-border)",
                    }
              }
            >
              {msg.isError && (
                <AlertCircle size={14} className="inline mr-1 mb-0.5" />
              )}
              {/* Render as plain text — no client-side tool interpretation (D3.2) */}
              <span style={{ whiteSpace: "pre-wrap" }}>{msg.content}</span>
            </div>
          </div>
        ))}

        {mutation.isPending && (
          <div className="flex justify-start">
            <div
              className="flex items-center gap-2 rounded-2xl rounded-bl-sm px-4 py-2.5 text-sm"
              style={{
                background: "var(--color-bg-subtle)",
                border: "1px solid var(--color-border)",
                color: "var(--color-fg-muted)",
              }}
            >
              <Loader2 size={14} className="animate-spin" />
              <span>Thinking…</span>
            </div>
          </div>
        )}

        <div ref={bottomRef} />
      </div>

      {/* Input */}
      <div
        className="px-4 py-3 border-t"
        style={{ borderColor: "var(--color-border)", background: "var(--color-bg-subtle)" }}
      >
        <div
          className="flex items-end gap-2 rounded-2xl border px-3 py-2"
          style={{
            borderColor: "var(--color-border)",
            background: "var(--color-bg-subtle)",
          }}
        >
          <textarea
            ref={inputRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask about your portfolio…"
            rows={1}
            className="flex-1 resize-none bg-transparent text-sm outline-none"
            style={{
              color: "var(--color-fg-default)",
              maxHeight: "120px",
              lineHeight: "1.5",
            }}
            disabled={mutation.isPending}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || mutation.isPending}
            className="shrink-0 rounded-full p-1.5 transition-colors disabled:opacity-40"
            style={{
              background: input.trim() && !mutation.isPending
                ? "var(--color-accent-blue)"
                : "var(--color-bg-muted)",
              color: input.trim() && !mutation.isPending ? "#fff" : "var(--color-fg-subtle)",
            }}
            aria-label="Send message"
          >
            <Send size={16} />
          </button>
        </div>
        <p className="text-center text-[10px] mt-1.5" style={{ color: "var(--color-fg-subtle)" }}>
          Press Enter to send · Shift+Enter for new line
        </p>
      </div>
    </div>
  );
}

import { useState, useCallback } from "react";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { CheckCircle, XCircle } from "lucide-react";
import { triggerJob, fetchJobs } from "../api/jobs";
import { Card } from "../components/ui/Card";
import { JobCard } from "../components/jobs/JobCard";
import { SupersededJobBanner } from "../components/jobs/SupersededJobBanner";
import { Spinner } from "../components/ui/Spinner";
import { useToastStore } from "../store/toastStore";
import { usePreferencesStore } from "../store/preferencesStore";
import { t } from "../store/i18n";
import { TickerSearch } from "../components/ui/TickerSearch";
import type { Job, JobAction, TickerSelection } from "../types/api";

function ActionCard({
  icon,
  title,
  description,
  action,
  tickerRequired,
  onTrigger,
  blocked = false,
  blockedReason,
}: {
  icon: string;
  title: string;
  description: string;
  action: JobAction;
  tickerRequired?: boolean;
  onTrigger: (job: Job) => void;
  blocked?: boolean;
  blockedReason?: string;
}) {
  const language = usePreferencesStore((s) => s.language);
  const queryClient = useQueryClient();
  const [tickerSelection, setTickerSelection] = useState<TickerSelection | null>(null);
  const [loading, setLoading] = useState(false);
  const showToast = useToastStore((s) => s.show);

  const handleTrigger = async () => {
    if (blocked) {
      showToast(blockedReason ?? "This feature is currently blocked.", "info");
      return;
    }
    if (tickerRequired && !tickerSelection) {
      showToast(t("tickerRequired", language), "warning");
      return;
    }
    setLoading(true);
    try {
      const res = await triggerJob(action, tickerRequired ? tickerSelection?.symbol : undefined);
      void queryClient.invalidateQueries({ queryKey: ["balance"] });
      onTrigger(res.job);
      showToast(`${title} — ${t("jobQueued", language)}`, "success");
      if (tickerRequired) setTickerSelection(null);
    } catch (err: unknown) {
      const axiosErr = err as { response?: { data?: { reason?: string; error?: string } } };
      const reason = axiosErr.response?.data?.reason || axiosErr.response?.data?.error;
      showToast(reason || `${t("jobFailed", language)}: ${action}`, "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Card className="p-4 flex flex-col gap-2">
      <div className="text-2xl">{icon}</div>
      <div>
        <h3 className="text-sm font-bold text-[var(--color-fg-default)]">{title}</h3>
        <p className="text-[10px] text-[var(--color-fg-muted)] mt-0.5">{description}</p>
      </div>
      {tickerRequired && (
        <div className="mt-1">
          <TickerSearch
            value={tickerSelection}
            onChange={setTickerSelection}
            placeholder={t("enterTicker", language)}
            disabled={blocked}
          />
        </div>
      )}
      {blockedReason ? (
        <div className="rounded-lg border border-dashed border-[var(--color-border)] bg-[var(--color-bg-muted)] px-3 py-2 text-[10px] leading-5 text-[var(--color-fg-muted)]">
          {blockedReason}
        </div>
      ) : null}
      <button
        onClick={handleTrigger}
        disabled={blocked || loading || (tickerRequired && !tickerSelection)}
        className={`w-full py-2 rounded-lg text-xs font-bold disabled:opacity-50 mt-1 ${
          blocked
            ? "border border-[var(--color-border)] bg-[var(--color-bg-muted)] text-[var(--color-fg-subtle)]"
            : "bg-[var(--color-accent-blue)] text-white"
        }`}
      >
        {blocked ? t("comingSoon", language) : loading ? "..." : t("run", language)}
      </button>
    </Card>
  );
}

export function Controls() {
  const language = usePreferencesStore((s) => s.language);
  const queryClient = useQueryClient();
  const showToast = useToastStore((s) => s.show);

  const { data: jobsData } = useQuery({
    queryKey: ["jobs"],
    queryFn: fetchJobs,
    staleTime: 30_000,
    refetchInterval: 30_000, // auto-refresh every 30s
  });

  const allJobs = jobsData?.jobs ?? [];

  // Jobs that are currently active (pending or running)
  const activeJobs = allJobs.filter((j) => j.status === "pending" || j.status === "paused" || j.status === "running");
  // Most recent completed/failed jobs
  const recentHistory = allJobs
    .filter((j) => j.status === "completed" || j.status === "partial_completed" || j.status === "failed")
    .slice(0, 15);

  const handleJobComplete = useCallback((job: Job) => {
    const label = job.action.replace(/_/g, " ");
    const ticker = job.ticker ? ` (${job.ticker})` : "";
    if (job.status === "completed") {
      showToast(`${label}${ticker} ${t("jobCompletedNotif", language)}`, "success");
    } else if (job.status === "partial_completed") {
      showToast(`${label}${ticker} completed partially — check failed tickers`, "warning");
    } else {
      showToast(`${label}${ticker} ${t("jobFailedNotif", language)}`, "error");
    }
    // Refresh the jobs list to update UI
    queryClient.invalidateQueries({ queryKey: ["jobs"] });
  }, [showToast, queryClient]);

  return (
    <>
      <div style={{ padding: "20px 16px 0" }}>
        <h1 style={{ fontSize: "var(--text-lg)", fontWeight: "var(--weight-bold)", color: "var(--text-primary)", margin: 0 }}>
          {t("controls", language)}
        </h1>
      </div>

      <div className="px-4 pt-3 pb-4">
        <SupersededJobBanner jobs={allJobs} />

        {/* Action grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
          <ActionCard
            icon="📋"
            title={t("jobDailyTitle", language)}
            description={t("jobDailyDesc", language)}
            action="daily_brief"
            onTrigger={() => {}}
          />
          <ActionCard
            icon="📊"
            title={t("jobWeeklyTitle", language)}
            description={t("jobWeeklyDesc", language)}
            action="full_report"
            onTrigger={() => {}}
            blocked
            blockedReason={t("jobWeeklyBlockedReason", language)}
          />
          <ActionCard
            icon="🔬"
            title={t("jobDeepDiveTitle", language)}
            description={t("jobDeepDiveDesc", language)}
            action="deep_dive"
            tickerRequired
            onTrigger={() => {}}
          />
          <ActionCard
            icon="💡"
            title={t("jobNewIdeasTitle", language)}
            description={t("jobNewIdeasDesc", language)}
            action="new_ideas"
            onTrigger={() => {}}
            blocked
            blockedReason={t("jobNewIdeasBlockedReason", language)}
          />
        </div>

        {/* Active jobs */}
        {activeJobs.length > 0 && (
          <div className="mt-5 space-y-2">
            <h2 className="text-xs font-bold text-[var(--color-fg-default)] uppercase border-l-2 border-[var(--color-accent-blue)] pl-2">
              {t("activeJobs", language)} ({activeJobs.length})
            </h2>
            {activeJobs.map((job) => (
              <JobCard
                key={job.id}
                job={job}
                onPollComplete={handleJobComplete}
              />
            ))}
          </div>
        )}

        {/* Job history */}
        <div className="mt-6">
          <h2 className="text-xs font-bold text-[var(--color-fg-subtle)] uppercase mb-3">
            {t("recentJobs", language)}
          </h2>

          {!jobsData ? (
            <div className="flex items-center justify-center py-8">
              <Spinner size="sm" />
            </div>
          ) : recentHistory.length === 0 && activeJobs.length === 0 ? (
            <div className="text-center py-10">
              <p className="text-3xl mb-2">📋</p>
              <p className="text-xs text-[var(--color-fg-muted)]">{t("noJobs", language)}</p>
            </div>
          ) : (
            <div className="space-y-1.5">
              {recentHistory.map((job) => (
                <div
                  key={job.id}
                  className="flex items-center justify-between gap-3 px-3 py-2.5 rounded-lg hover:bg-[var(--color-bg-subtle)]"
                >
                  <div className="flex items-center gap-2 min-w-0">
                    <span className="shrink-0">
                      {job.status === "completed" || job.status === "partial_completed"
                        ? <CheckCircle size={14} className="text-[var(--color-accent-green)]" />
                        : <XCircle size={14} className="text-[var(--color-accent-red)]" />}
                    </span>
                    <span className="text-xs font-medium text-[var(--color-fg-default)] truncate">
                      {job.action.replace(/_/g, " ")}
                      {job.ticker && (
                        <span className="text-[var(--color-fg-muted)]"> · {job.ticker}</span>
                      )}
                    </span>
                  </div>
                  <span className="text-[10px] text-[var(--color-fg-subtle)] shrink-0">
                    {new Date(job.completed_at ?? job.triggered_at).toLocaleString("en-US", {
                      month: "short",
                      day: "numeric",
                      hour: "numeric",
                      minute: "2-digit",
                    })}
                  </span>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}

